1126	/// the length is not an integer.
1127	///
1128	/// C: `LUALIB_API lua_Integer luaL_len(lua_State *L, int idx)`
1129	pub fn lua_len(state: &mut LuaState, idx: i32) -> Result<i64, LuaError> {
1130	    // C: lua_len(L, idx);
1131	    state.len_op(idx)?;
1132	    // C: l = lua_tointegerx(L, -1, &isnum);
1133	    let l = match state.to_integer_x(-1) {
1134	        Some(n) => n,
1135	        None => {
1136	            return Err(LuaError::runtime(format_args!(
1137	                "object length is not an integer"
1138	            )));
1139	        }
1140	    };
1141	    // C: lua_pop(L, 1);
1142	    state.pop_n(1);
