            get_metatable(state, tname)?;
            // C: if (!lua_rawequal(L, -1, -2))  p = NULL;
            let eq = state.raw_equal(-1, -2)?;
            state.pop_n(2); // remove both metatables
            if eq {
                return Ok(Some(p));
            }
