        lua_vm::api::check_stack(self, nup);
        for (name, f) in funcs {
            for _ in 0..nup {
                lua_vm::api::push_value(self, -nup);
            }
            lua_vm::api::push_cclosure(self, *f, nup)?;
            lua_vm::api::set_field(self, -(nup + 2), name)?;
        }
        self.pop_n(nup as usize);
        Ok(())
    }

