            return Ok(LuaType::Nil);
        }
        lua_vm::api::push_lstring(self, name)?;
        let tt = lua_vm::api::raw_get(self, -2);
        if tt == LuaType::Nil {
            self.pop_n(2);
        } else {
            self.remove(-2)?;
        }
        Ok(tt)
