    fn check_arg_option(
        &mut self,
        arg: i32,
        def: Option<&[u8]>,
        lst: &[&[u8]],
    ) -> Result<usize, LuaError> {
        let name: Vec<u8> = match def {
            Some(d) if matches!(
                lua_vm::api::lua_type_at(self, arg),
                LuaType::None | LuaType::Nil
            ) =>
            {
                d.to_vec()
            }
            _ => self.check_arg_string(arg)?,
        };
        for (i, entry) in lst.iter().enumerate() {
            if *entry == name.as_slice() {
                return Ok(i);
