        let mut out: Vec<u8> = Vec::new();
        let mut writer = |chunk: &[u8]| -> Result<(), LuaError> {
            out.extend_from_slice(chunk);
            Ok(())
        };
        lua_vm::api::dump(self, &mut writer, strip)?;
        Ok(out)
